1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string; cursed?: boolean }[] }): number {
16	  if (input.items.length === 0) return PROCESSING_FEE;
17	  const groups = new Map<string, { type: string; cursed?: boolean }[]>();
18	  for (const item of input.items) {
19	    const list = groups.get(item.type) ?? [];
20	    list.push(item);
21	    groups.set(item.type, list);
22	  }
23	  let basePremium = 0;
24	  let firstInsurance = 0;
25	  for (const [type, items] of groups) {
26	    const count = items.length;
27	    if (COMPONENT_TYPES.has(type) && count === 3) {
28	      basePremium += 60;
29	      firstInsurance += 60 * FIRST_INSURANCE_RATE;
30	    } else {
31	      for (const item of items) {
32	        const itemBase = BASE_PREMIUM_BY_TYPE[type];
33	        let itemContribution = itemBase;
34	        if (item.cursed) {
35	          itemContribution += itemBase * 0.5;
36	        }
37	        basePremium += itemContribution;
38	        firstInsurance += itemBase * FIRST_INSURANCE_RATE;
39	      }
40	    }
41	  }
42	  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
43	}
